from flask import Flask, request, jsonify
import psycopg2
from psycopg2.extras import RealDictCursor

app = Flask(__name__)

# Database connection parameters (keep sensitive data out of plaintext storage)
DB_HOST = 'your_db_host'
DB_NAME = 'your_db_name'
DB_USER = 'your_db_user'
DB_PASSWORD = 'your_db_password'

def get_db_connection():
    conn = psycopg2.connect(
        host=DB_HOST,
        database=DB_NAME,
        user=DB_USER,
        password=DB_PASSWORD
    )
    conn.autocommit = True
    return conn

@app.route('/query', methods=['GET'])
def query_data():
    table_name = request.args.get('table')
    columns = request.args.get('columns')
    filter_condition = request.args.get('filter')

    if not table_name or not columns:
        return jsonify({'error': 'Table name and columns are required'}), 400

    # Validate and sanitize input
    allowed_tables = ['users', 'orders', 'products']
    allowed_columns = {
        'users': ['id', 'name', 'email'],
        'orders': ['order_id', 'user_id', 'product_id', 'quantity'],
        'products': ['product_id', 'name', 'price']
    }

    if table_name not in allowed_tables:
        return jsonify({'error': 'Invalid table name'}), 400

    columns = [col for col in columns.split(',') if col.strip() in allowed_columns.get(table_name, [])]
    if not columns:
        return jsonify({'error': 'Invalid column names'}), 400

    if filter_condition and '=' in filter_condition:
        key, value = filter_condition.split('=')
        if key.strip() not in allowed_columns[table_name]:
            return jsonify({'error': 'Invalid filter condition'}), 400
        value = psycopg2.extras.adapt(value).getquoted().decode('utf-8')

    query = f"SELECT {', '.join(columns)} FROM {table_name}"
    if filter_condition:
        query += f" WHERE {filter_condition}"

    conn = get_db_connection()
    cur = conn.cursor(cursor_factory=RealDictCursor)
    try:
        cur.execute(query)
        result = cur.fetchall()
        return jsonify(result), 200
    except psycopg2.Error as e:
        return jsonify({'error': str(e)}), 500
    finally:
        cur.close()
        conn.close()

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)